const arr = $input.all();

const textObj = arr.find(item => item.json.content);
const imageObj = arr.find(item => item.json.image);

return {
  json: {
    text: textObj.json.content.parts[0].text,
    image: imageObj.json.image
  }
}

// Получаем данные из RSS
const article = $input.first().json;
const title = article.title?.toLowerCase() || '';
const description = article.contentSnippet?.toLowerCase() || '';
const content = title + ' ' + description;

// Расширенный список запрещенных слов на русском и английском
const bannedKeywords = [
  // ====== ПОЛИТИКА ======
  // Международная политика
  'trump', 'biden', 'putin', 'zelensky', 'кремл', 'белый дом', 'congress',
  'senate', 'парламент', 'правительство', 'администрация',

  // Военные конфликты
  'war', 'война', 'invasion', 'вторжение', 'military', 'военн', 'санкц',
  'sanction', 'nato', 'нато', 'оруж', 'weapon', 'армия',

  // Выборы и протесты
  'election', 'выбор', 'protest', 'протест', 'rally', 'митинг', 'революц',
  'revolution', 'impeachment', 'импичмент',

  // Политические термины
  'political', 'политик', 'democrat', 'republican', 'либерал', 'консерватив',
  'government', 'правительство', 'партия', 'party',

  // ====== 18+ КОНТЕНТ ======
  // Секс и отношения
  'sex', 'секс', 'porn', 'порно', 'xxx', 'erotic', 'эротик', 'intimate',
  'интим', 'adult', 'для взрослых', 'hooker', 'prostitut', 'проституц',
  'escort', 'эскорт', 'blowjob', 'минёт', 'handjob', 'orgasm', 'оргазм',

  // Анатомия и физиология
  'penis', 'пенис', 'dick', 'член', 'vagina', 'влагалище', 'pussy', 'киска',
  'breast', 'грудь', 'boob', 'сиськ', 'ass', 'задниц', 'butt', 'попа',

  // Насилие и преступления
  'rape', 'изнасилование', 'abuse', 'abus', 'насилие', 'murder', 'убийств',
  'corpse', 'труп', 'blood', 'кровь', 'violence', 'жестокость',

  // Наркотики и алкоголь
  'drug', 'наркотик', 'cocaine', 'кокаин', 'heroin', 'героин', 'marijuana',
  'марихуан', 'weed', 'алкогол', 'alcohol', 'пьян', 'drunk', 'hangover',

  // ====== НЕНАВИСТЬ И ДИСКРИМИНАЦИЯ ======
  'racist', 'расист', 'nazi', 'наци', 'fascist', 'фашист', 'homophob',
  'гомофоб', 'transphob', 'трансфоб', 'hate speech', 'ненавист',

  // ====== ШОК-КОНТЕНТ ======
  'gore', 'горе', 'massacre', 'резня', 'terror', 'террор', 'suicide',
  'самоубийство', 'accident', 'авария', 'catastrophe', 'катастроф'
];

// Проверяем каждый пункт из бана
const hasBannedContent = bannedKeywords.some(keyword => {
  return content.includes(keyword.toLowerCase());
});

// Дополнительная проверка по контексту (можно расширить)
const contextCheck = (text) => {
  const dangerousPatterns = [
    /(война|war).*(украин|russia)/i,
    /(политик|politic).*(скандал|scandal)/i,
    /(убийств|murder).*(дет|child)/i,
    /(наркотик|drug).*(продаж|deal)/i
  ];

  return dangerousPatterns.some(pattern => pattern.test(text));
};

// Финальное решение - баним статью
if (hasBannedContent || contextCheck(content)) {
  console.log('Статья заблокирована по содержанию:', title);
  return [];
}

// Если проверка пройдена - возвращаем статью
return $input.all();
